import{_ as e,c as d,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"版本历史: 功能演进 | opencode-agent-skills","description":"学习 OpenCode Agent Skills 插件的版本演进历史。本教程整理了从 v0.1.0 到 v0.6.4 的所有主要功能更新、Bug 修复、架构改进和重大变更说明。","frontmatter":{"title":"版本历史: 功能演进 | opencode-agent-skills","sidebarTitle":"新版本干了啥","subtitle":"版本历史","description":"学习 OpenCode Agent Skills 插件的版本演进历史。本教程整理了从 v0.1.0 到 v0.6.4 的所有主要功能更新、Bug 修复、架构改进和重大变更说明。","tags":["版本更新","changelog","发布历史"],"order":3},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/changelog/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/changelog/index.md"}'),l={name:"zh/joshuadavidthomas/opencode-agent-skills/changelog/index.md"};function r(i,t,s,n,c,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="版本历史" tabindex="-1">版本历史 <a class="header-anchor" href="#版本历史" aria-label="Permalink to &quot;版本历史&quot;">​</a></h1><p>本文档记录了 OpenCode Agent Skills 插件的所有版本更新。通过版本历史，你可以了解功能的演进路径、修复的问题以及架构改进。</p><div class="tip custom-block"><p class="custom-block-title">当前版本</p><p>最新稳定版本是 <strong>v0.6.4</strong> (2026-01-20)</p></div><h2 id="版本时间线" tabindex="-1">版本时间线 <a class="header-anchor" href="#版本时间线" aria-label="Permalink to &quot;版本时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>发布日期</th><th>类型</th><th>主要内容</th></tr></thead><tbody><tr><td>0.6.4</td><td>2026-01-20</td><td>修复</td><td>YAML 解析、Claude v2 支持</td></tr><tr><td>0.6.3</td><td>2025-12-16</td><td>改进</td><td>优化技能推荐提示</td></tr><tr><td>0.6.2</td><td>2025-12-15</td><td>修复</td><td>技能名称与目录名分离</td></tr><tr><td>0.6.1</td><td>2025-12-13</td><td>改进</td><td>避免重复推荐已加载技能</td></tr><tr><td>0.6.0</td><td>2025-12-12</td><td>新功能</td><td>语义匹配、embedding 预计算</td></tr><tr><td>0.5.0</td><td>2025-12-11</td><td>改进</td><td>模糊匹配建议、重构</td></tr><tr><td>0.4.1</td><td>2025-12-08</td><td>改进</td><td>简化安装方式</td></tr><tr><td>0.4.0</td><td>2025-12-05</td><td>改进</td><td>脚本递归搜索</td></tr><tr><td>0.3.3</td><td>2025-12-02</td><td>修复</td><td>符号链接处理</td></tr><tr><td>0.3.2</td><td>2025-11-30</td><td>修复</td><td>保留代理模式</td></tr><tr><td>0.3.1</td><td>2025-11-28</td><td>修复</td><td>模型切换问题</td></tr><tr><td>0.3.0</td><td>2025-11-27</td><td>新功能</td><td>文件列表功能</td></tr><tr><td>0.2.0</td><td>2025-11-26</td><td>新功能</td><td>Superpowers 模式</td></tr><tr><td>0.1.0</td><td>2025-11-26</td><td>初始</td><td>4 个工具、多位置发现</td></tr></tbody></table><h2 id="详细变更记录" tabindex="-1">详细变更记录 <a class="header-anchor" href="#详细变更记录" aria-label="Permalink to &quot;详细变更记录&quot;">​</a></h2><h3 id="v0-6-4-2026-01-20" tabindex="-1">v0.6.4 (2026-01-20) <a class="header-anchor" href="#v0-6-4-2026-01-20" aria-label="Permalink to &quot;v0.6.4 (2026-01-20)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>修复了技能多行描述的 YAML frontmatter 解析（支持 <code>|</code> 和 <code>&gt;</code> 块标量语法），通过用 <code>yaml</code> 库替换自定义解析器</li><li>新增对 Claude 插件 v2 格式的支持，<code>installed_plugins.json</code> 现在使用插件安装数组而非单个对象</li></ul><p><strong>改进</strong>：</p><ul><li>Claude Code 插件缓存发现现在支持新的嵌套目录结构（<code>cache/&lt;marketplace&gt;/&lt;plugin&gt;/&lt;version&gt;/skills/</code>）</li></ul><h3 id="v0-6-3-2025-12-16" tabindex="-1">v0.6.3 (2025-12-16) <a class="header-anchor" href="#v0-6-3-2025-12-16" aria-label="Permalink to &quot;v0.6.3 (2025-12-16)&quot;">​</a></h3><p><strong>改进</strong>：</p><ul><li>优化了技能评估提示，防止模型向用户发送&quot;无需技能&quot;类消息（用户看不到隐藏的评估提示）</li></ul><h3 id="v0-6-2-2025-12-15" tabindex="-1">v0.6.2 (2025-12-15) <a class="header-anchor" href="#v0-6-2-2025-12-15" aria-label="Permalink to &quot;v0.6.2 (2025-12-15)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>技能验证现在允许目录名与 SKILL.md frontmatter 中的 <code>name</code> 不同。frontmatter 中的 <code>name</code> 是标准标识符，目录名仅用于组织。这符合 Anthropic Agent Skills 规范。</li></ul><h3 id="v0-6-1-2025-12-13" tabindex="-1">v0.6.1 (2025-12-13) <a class="header-anchor" href="#v0-6-1-2025-12-13" aria-label="Permalink to &quot;v0.6.1 (2025-12-13)&quot;">​</a></h3><p><strong>改进</strong>：</p><ul><li>动态技能推荐现在会跟踪每个会话已加载的技能，避免重复推荐已加载技能，减少冗余提示和上下文使用</li></ul><h3 id="v0-6-0-2025-12-12" tabindex="-1">v0.6.0 (2025-12-12) <a class="header-anchor" href="#v0-6-0-2025-12-12" aria-label="Permalink to &quot;v0.6.0 (2025-12-12)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li><strong>语义技能匹配</strong>：在初始技能列表注入后，后续消息会使用本地 embedding 与技能描述进行匹配</li><li>新增 <code>@huggingface/transformers</code> 依赖用于本地 embedding 生成（量化版 all-MiniLM-L6-v2）</li><li>当消息匹配可用技能时，注入 3 步评估提示（EVALUATE → DECIDE → ACTIVATE），鼓励加载技能（灵感来自 <a href="https://github.com/spences10" target="_blank" rel="noreferrer">@spences10</a> 的<a href="https://scottspence.com/posts/how-to-make-claude-code-skills-activate-reliably" target="_blank" rel="noreferrer">博客文章</a>）</li><li>磁盘缓存 embedding 以实现低延迟匹配（~/.cache/opencode-agent-skills/）</li><li>在 <code>session.deleted</code> 事件上清理会话</li></ul><h3 id="v0-5-0-2025-12-11" tabindex="-1">v0.5.0 (2025-12-11) <a class="header-anchor" href="#v0-5-0-2025-12-11" aria-label="Permalink to &quot;v0.5.0 (2025-12-11)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>在所有工具（<code>use_skill</code>、<code>read_skill_file</code>、<code>run_skill_script</code>、<code>get_available_skills</code>）中添加&quot;你是否指...&quot;模糊匹配建议</li></ul><p><strong>改进</strong>：</p><ul><li><strong>破坏性变更</strong>：将 <code>find_skills</code> 工具重命名为 <code>get_available_skills</code>，意图更明确</li><li><strong>内部</strong>：将代码库重组为独立模块（<code>claude.ts</code>、<code>skills.ts</code>、<code>tools.ts</code>、<code>utils.ts</code>、<code>superpowers.ts</code>），提高可维护性</li><li><strong>内部</strong>：通过删除 AI 生成的注释和不必要的代码，提高代码质量</li></ul><h3 id="v0-4-1-2025-12-08" tabindex="-1">v0.4.1 (2025-12-08) <a class="header-anchor" href="#v0-4-1-2025-12-08" aria-label="Permalink to &quot;v0.4.1 (2025-12-08)&quot;">​</a></h3><p><strong>改进</strong>：</p><ul><li>安装方式现在通过 OpenCode config 使用 npm 包，而非 git clone + 符号链接</li></ul><p><strong>移除</strong>：</p><ul><li>移除了 <code>INSTALL.md</code>（简化安装后不再需要）</li></ul><h3 id="v0-4-0-2025-12-05" tabindex="-1">v0.4.0 (2025-12-05) <a class="header-anchor" href="#v0-4-0-2025-12-05" aria-label="Permalink to &quot;v0.4.0 (2025-12-05)&quot;">​</a></h3><p><strong>改进</strong>：</p><ul><li>脚本发现现在递归搜索整个技能目录（最大深度 10），而非仅根目录和 <code>scripts/</code> 子目录</li><li>脚本现在通过相对路径（如 <code>tools/build.sh</code>）而非基本名称识别</li><li>在 <code>read_skill_file</code>、<code>run_skill_script</code> 和 <code>use_skill</code> 工具中将 <code>skill_name</code> 参数重命名为 <code>skill</code></li><li>在 <code>run_skill_script</code> 工具中将 <code>script_name</code> 参数重命名为 <code>script</code></li></ul><h3 id="v0-3-3-2025-12-02" tabindex="-1">v0.3.3 (2025-12-02) <a class="header-anchor" href="#v0-3-3-2025-12-02" aria-label="Permalink to &quot;v0.3.3 (2025-12-02)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>通过使用 <code>fs.stat</code> 修复了文件和目录检测以正确处理符号链接</li></ul><h3 id="v0-3-2-2025-11-30" tabindex="-1">v0.3.2 (2025-11-30) <a class="header-anchor" href="#v0-3-2-2025-11-30" aria-label="Permalink to &quot;v0.3.2 (2025-11-30)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>在会话开始时注入合成消息时保留代理模式</li></ul><h3 id="v0-3-1-2025-11-28" tabindex="-1">v0.3.1 (2025-11-28) <a class="header-anchor" href="#v0-3-1-2025-11-28" aria-label="Permalink to &quot;v0.3.1 (2025-11-28)&quot;">​</a></h3><p><strong>修复</strong>：</p><ul><li>通过在 <code>noReply</code> 操作中显式传递当前模型，修复了使用技能工具时的意外模型切换（针对 opencode issue #4475 的临时方案）</li></ul><h3 id="v0-3-0-2025-11-27" tabindex="-1">v0.3.0 (2025-11-27) <a class="header-anchor" href="#v0-3-0-2025-11-27" aria-label="Permalink to &quot;v0.3.0 (2025-11-27)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>在 <code>use_skill</code> 输出中添加文件列表</li></ul><h3 id="v0-2-0-2025-11-26" tabindex="-1">v0.2.0 (2025-11-26) <a class="header-anchor" href="#v0-2-0-2025-11-26" aria-label="Permalink to &quot;v0.2.0 (2025-11-26)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>新增 Superpowers 模式支持</li><li>新增发布证明</li></ul><h3 id="v0-1-0-2025-11-26" tabindex="-1">v0.1.0 (2025-11-26) <a class="header-anchor" href="#v0-1-0-2025-11-26" aria-label="Permalink to &quot;v0.1.0 (2025-11-26)&quot;">​</a></h3><p><strong>新增</strong>：</p><ul><li>新增 <code>use_skill</code> 工具，将技能内容加载到上下文</li><li>新增 <code>read_skill_file</code> 工具，读取技能目录中的支持文件</li><li>新增 <code>run_skill_script</code> 工具，从技能目录执行脚本</li><li>新增 <code>find_skills</code> 工具，搜索并列出可用技能</li><li>新增多位置技能发现（项目级、用户级和 Claude 兼容位置）</li><li>新增符合 Anthropic Agent Skills Spec v1.0 的 frontmatter 验证</li><li>新增会话开始和上下文压缩后的自动技能列表注入</li></ul><p><strong>新贡献者</strong>：</p><ul><li>Josh Thomas <a href="mailto:josh@joshthomas.dev" target="_blank" rel="noreferrer">josh@joshthomas.dev</a> (维护者)</li></ul><h2 id="功能演进概览" tabindex="-1">功能演进概览 <a class="header-anchor" href="#功能演进概览" aria-label="Permalink to &quot;功能演进概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>引入版本</th><th>演进路径</th></tr></thead><tbody><tr><td>4 个基础工具</td><td>v0.1.0</td><td>v0.5.0 添加模糊匹配</td></tr><tr><td>多位置技能发现</td><td>v0.1.0</td><td>v0.4.1 简化安装、v0.6.4 支持 Claude v2</td></tr><tr><td>上下文自动注入</td><td>v0.1.0</td><td>v0.3.0 添加文件列表、v0.6.1 避免重复推荐</td></tr><tr><td>Superpowers 模式</td><td>v0.2.0</td><td>持续稳定</td></tr><tr><td>脚本递归搜索</td><td>v0.4.0</td><td>v0.3.3 修复符号链接</td></tr><tr><td>语义匹配推荐</td><td>v0.6.0</td><td>v0.6.1 避免重复、v0.6.3 优化提示</td></tr><tr><td>模糊匹配建议</td><td>v0.5.0</td><td>持续稳定</td></tr></tbody></table><h2 id="重大变更说明" tabindex="-1">重大变更说明 <a class="header-anchor" href="#重大变更说明" aria-label="Permalink to &quot;重大变更说明&quot;">​</a></h2><h3 id="v0-6-0-语义匹配功能" tabindex="-1">v0.6.0：语义匹配功能 <a class="header-anchor" href="#v0-6-0-语义匹配功能" aria-label="Permalink to &quot;v0.6.0：语义匹配功能&quot;">​</a></h3><p>引入了基于本地 embedding 的语义匹配能力，让 AI 能够根据用户消息内容自动推荐相关技能，无需用户手动记忆技能名称。</p><ul><li><strong>技术细节</strong>：使用 HuggingFace 的 <code>all-MiniLM-L6-v2</code> 模型（q8 量化）</li><li><strong>缓存机制</strong>：embedding 结果缓存到 <code>~/.cache/opencode-agent-skills/</code>，提升后续匹配速度</li><li><strong>匹配流程</strong>：用户消息 → embedding → 与技能描述计算余弦相似度 → Top 5 推荐（阈值 0.35）</li></ul><h3 id="v0-5-0-重构与工具重命名" tabindex="-1">v0.5.0：重构与工具重命名 <a class="header-anchor" href="#v0-5-0-重构与工具重命名" aria-label="Permalink to &quot;v0.5.0：重构与工具重命名&quot;">​</a></h3><p>代码架构重构为模块化设计，工具命名更加清晰：</p><ul><li><code>find_skills</code> → <code>get_available_skills</code></li><li><code>skill_name</code> → <code>skill</code></li><li><code>script_name</code> → <code>script</code></li></ul><h3 id="v0-4-0-脚本发现机制升级" tabindex="-1">v0.4.0：脚本发现机制升级 <a class="header-anchor" href="#v0-4-0-脚本发现机制升级" aria-label="Permalink to &quot;v0.4.0：脚本发现机制升级&quot;">​</a></h3><p>脚本发现从&quot;仅根目录 + scripts/&quot;升级为&quot;递归搜索整个技能目录&quot;（最大深度 10），支持更灵活的脚本组织方式。</p><h3 id="v0-2-0-superpowers-集成" tabindex="-1">v0.2.0：Superpowers 集成 <a class="header-anchor" href="#v0-2-0-superpowers-集成" aria-label="Permalink to &quot;v0.2.0：Superpowers 集成&quot;">​</a></h3><p>新增对 Superpowers 工作流模式的支持，需要安装 <code>using-superpowers</code> 技能并设置环境变量 <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code>。</p><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>当前版本号</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/package.json#L3-L3" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>3</td></tr><tr><td>版本历史</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/CHANGELOG.md#L19-L152" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td><td>19-152</td></tr></tbody></table><p><strong>关键版本信息</strong>：</p><ul><li><code>v0.6.4</code>：当前版本 (2026-01-20)</li><li><code>v0.6.0</code>：语义匹配引入 (2025-12-12)</li><li><code>v0.5.0</code>：重构版本 (2025-12-11)</li><li><code>v0.1.0</code>：初始版本 (2025-11-26)</li></ul></details>',72)])])}const v=e(l,[["render",r]]);export{p as __pageData,v as default};
